		require.NoError(t, err)
		defer func() { _ = srcFile.Close() }()

		destFile, err := os.Create(destBinary)
		require.NoError(t, err)
		defer func() { _ = destFile.Close() }()

		_, err = io.Copy(destFile, srcFile)
		require.NoError(t, err)

